 22→function getCaptionClearance(viewport) {
 23→  if (viewport?.captionPosition === 'above' || viewport?.captionPosition === 'below') {
 24→    return SHEET_TOKENS.viewportCaptionGap + SHEET_TOKENS.viewportCaptionHeight;
 25→  }
 26→  return 0;
