 29→function buildSheetZones(paper) {
 30→  const border = {
 31→    x: SHEET_TOKENS.margin,
 32→    y: SHEET_TOKENS.margin,
 33→    width: paper.width - SHEET_TOKENS.margin * 2,
 34→    height: paper.height - SHEET_TOKENS.margin * 2,
 35→  };
 36→
 37→  const liveArea = {
 38→    x: border.x + SHEET_TOKENS.innerInset,
 39→    y: border.y + SHEET_TOKENS.innerInset,
 40→    width: border.width - SHEET_TOKENS.innerInset * 2,
 41→    height: border.height - SHEET_TOKENS.innerInset * 2,
 42→  };
 43→
 44→  const footer = {
 45→    x: liveArea.x,
 46→    y: liveArea.y + liveArea.height - SHEET_TOKENS.footerHeight,
 47→    width: liveArea.width,
 48→    height: SHEET_TOKENS.footerHeight,
 49→  };
 50→
 51→  const contentArea = {
 52→    x: liveArea.x,
 53→    y: liveArea.y,
 54→    width: liveArea.width,
 55→    height: footer.y - liveArea.y - SHEET_TOKENS.contentGap,
 56→  };
 57→
 58→  const titleBlock = {
 59→    x: footer.x + footer.width - Math.min(SHEET_TOKENS.titleBlockWidth, footer.width * 0.46),
 60→    y: footer.y,
 61→    width: Math.min(SHEET_TOKENS.titleBlockWidth, footer.width * 0.46),
 62→    height: footer.height,
 63→  };
 64→
 65→  return {
 66→    border,
 67→    liveArea,
 68→    footer,
 69→    contentArea,
 70→    titleBlock,
 71→  };
 72→}
 73→
 74→function resolveViewportTitle(viewport, source) {
 75→  return viewport.title?.trim() || source.title || getViewportSourceLabel(viewport.sourceView);
 76→}
 77→
 78→function formatCaptionSecondary(viewport, source, sheet) {
 79→  const scaleLabel = resolveViewportScaleLabel(viewport, source, sheet);
 80→  const reference = resolveViewportReferenceNote(viewport, source);
 81→  return `${reference}  |  SCALE ${scaleLabel}`;
 82→}
 83→
 84→function buildContentTransform(viewport, source, contentRect) {
 85→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
 86→  const sourceWidth = Math.max(1, bounds.maxX - bounds.minX);
 87→  const sourceHeight = Math.max(1, bounds.maxY - bounds.minY);
 88→  const scale = source.kind === '3d_preview'
 89→    ? Math.min(contentRect.width / sourceWidth, contentRect.height / sourceHeight)
 90→    : (1 / resolveViewportScale(viewport));
 91→
 92→  const drawnWidth = sourceWidth * scale;
 93→  const drawnHeight = sourceHeight * scale;
 94→  const translateX = (contentRect.width - drawnWidth) / 2 - bounds.minX * scale;
 95→  const translateY = (contentRect.height - drawnHeight) / 2 - bounds.minY * scale;
 96→
 97→  return {
 98→    scale,
 99→    translateX,
100→    translateY,
101→  };
102→}
103→
104→function buildViewportScene(viewport, source, sheet, rect) {
105→  const frameRect = snapRectToGrid(rect);
106→  const contentRect = {
107→    x: frameRect.x + SHEET_TOKENS.viewportPadding,
108→    y: frameRect.y + SHEET_TOKENS.viewportPadding,
109→    width: Math.max(10, frameRect.width - SHEET_TOKENS.viewportPadding * 2),
110→    height: Math.max(10, frameRect.height - SHEET_TOKENS.viewportPadding * 2),
111→  };
112→
113→  const captionGap = SHEET_TOKENS.viewportCaptionGap;
114→  const captionHeight = SHEET_TOKENS.viewportCaptionHeight;
115→  const captionY = viewport.captionPosition === 'above'
116→    ? frameRect.y - captionGap
117→    : frameRect.y + frameRect.height + captionGap + captionHeight;
118→
119→  const caption = {
120→    position: viewport.captionPosition || 'below',
121→    x: frameRect.x,
122→    y: captionY,
123→    width: frameRect.width,
124→    primaryText: resolveViewportTitle(viewport, source),
125→    secondaryText: formatCaptionSecondary(viewport, source, sheet),
126→  };
127→
128→  return {
129→    ...viewport,
130→    x: frameRect.x,
131→    y: frameRect.y,
132→    width: frameRect.width,
133→    height: frameRect.height,
134→    title: caption.primaryText,
135→    source,
136→    frameRect,
137→    clipRect: contentRect,
138→    contentRect,
139→    caption,
140→    contentTransform: buildContentTransform(viewport, source, contentRect),
141→    autoLayoutApplied: !viewport.lockAutoLayout,
142→  };
143→}
