169→      width: mainWidth * 0.68,
170→      height: titleHeight,
171→      label: 'DRAWING TITLE',
172→      value: meta.drawingTitle,
173→    },
174→    numberCell: {
175→      x: titleBlockRect.x + mainWidth * 0.68,
176→      y: titleBlockRect.y + bandHeight,
177→      width: mainWidth * 0.32,
178→      height: titleHeight,
179→      label: 'SHEET NO.',
180→      value: meta.sheetNumber,
181→    },
182→    metaRows: [
183→      {
184→        x: titleBlockRect.x,
185→        y: titleBlockRect.y + bandHeight + titleHeight,
186→        width: mainWidth / 2,
187→        height: metaRowHeight,
188→        labelWidth: metaLabelWidth,
189→        label: 'DATE',
190→        value: meta.issueDate,
191→      },
192→      {
193→        x: titleBlockRect.x + mainWidth / 2,
194→        y: titleBlockRect.y + bandHeight + titleHeight,
195→        width: mainWidth / 2,
196→        height: metaRowHeight,
197→        labelWidth: metaLabelWidth,
198→        label: 'SCALE',
199→        value: meta.scaleLabel,
200→      },
201→      {
202→        x: titleBlockRect.x,
