308→          viewBox={`0 0 ${scene.paper.width} ${scene.paper.height}`}
309→          style={{
310→            position: 'absolute',
311→            width: 0,
312→            height: 0,
313→            overflow: 'hidden',
314→            pointerEvents: 'none',
315→            opacity: 0,
316→          }}
317→          aria-hidden="true"
318→        >
319→          <SheetRenderer
320→            project={project}
321→            sheet={sheet}
322→            selectedId={null}
323→            selectedType={null}
