400→          l.id === action.landing.id ? { ...l, ...action.landing } : l
401→        );
402→        // Cascade: sync all stairs attached to this landing
403→        const nextStairs = (f.stairs || []).map(stair => {
404→          const attachedToStart = stair.startLandingAttachment?.landingId === action.landing.id;
405→          const attachedToEnd = stair.endLandingAttachment?.landingId === action.landing.id;
406→          if (!attachedToStart && !attachedToEnd) return stair;
