434→
435→    case 'ANNOTATION_UPDATE':
436→      return updateFloor(state, action.floorId, f => ({
437→        ...f,
438→        annotations: (f.annotations || []).map((annotation) => (
439→          annotation.id === action.annotation.id ? { ...annotation, ...action.annotation } : annotation
440→        )),
441→      }));
442→
443→    case 'ANNOTATION_DELETE':
444→      return updateFloor(state, action.floorId, f => ({
